refentry.refsect1:
  &reftitle.examples;



    Memcache::setSaslAuthData example


<?php
/* OO API, requires memcache.protocol=binary */

$memcache_obj = new Memcache;

/* set the SASL credentials before adding the server */
$memcache_obj->setSaslAuthData('user', 'password');

$memcache_obj->addServer('memcache_host', 11211);

$memcache_obj->set('var_key', 'some variable');
echo $memcache_obj->get('var_key');

?>




    memcache_set_sasl_auth_data example


<?php
/* procedural API, requires memcache.protocol=binary */

$memcache_obj = new Memcache;

memcache_set_sasl_auth_data($memcache_obj, 'user', 'password');

memcache_add_server($memcache_obj, 'memcache_host', 11211);

memcache_set($memcache_obj, 'var_key', 'some variable');
echo memcache_get($memcache_obj, 'var_key');

?>
